const setup = $('⚙️ Setup').first().json;

function statistik(orders) {
  orders = (orders || []).filter(o => !o.cancelled_at);
  let umsatz = 0;
  let neukunden = 0;
  let stammkunden = 0;
  const produkte = {};
  for (const o of orders) {
    umsatz += parseFloat(o.total_price || 0);
    if (o.customer && parseInt(o.customer.orders_count || 1) <= 1) neukunden++; else stammkunden++;
    for (const li of (o.line_items || [])) produkte[li.title] = (produkte[li.title] || 0) + li.quantity;
  }
  const top = Object.entries(produkte).sort((a, b) => b[1] - a[1]).slice(0, 5)
    .map(([n, m]) => n + ' (' + m + 'x)').join(', ');
  return { umsatz, anzahl: orders.length, aov: orders.length ? umsatz / orders.length : 0, neukunden, stammkunden, top };
}

const woche = statistik($('📥 Diese Woche').first().json.orders);
const vorwoche = statistik($('📥 Vorwoche').first().json.orders);

function delta(a, b) {
  if (!b) return a > 0 ? '+∞' : '0%';
  return ((a - b) / b * 100).toFixed(0) + '%';
}

const daten = 'DIESE WOCHE: Umsatz ' + woche.umsatz.toFixed(2) + ' | Bestellungen ' + woche.anzahl + ' | AOV ' + woche.aov.toFixed(2) + ' | Neukunden ' + woche.neukunden + ' | Stammkunden ' + woche.stammkunden + '\n' +
  'VORWOCHE: Umsatz ' + vorwoche.umsatz.toFixed(2) + ' | Bestellungen ' + vorwoche.anzahl + ' | AOV ' + vorwoche.aov.toFixed(2) + '\n' +
  'VERAENDERUNG: Umsatz ' + delta(woche.umsatz, vorwoche.umsatz) + ' | Bestellungen ' + delta(woche.anzahl, vorwoche.anzahl) + '\n' +
  'TOP-PRODUKTE: ' + (woche.top || 'keine') + '\n' +
  'MONATSZIEL: ' + setup.MONATSZIEL_UMSATZ + ' Umsatz | MARKETING-BUDGET: ' + setup.MARKETING_BUDGET_MONAT + '/Monat';

const prompt = 'Du bist der CMO (Marketing-Chef) vom Onlineshop "' + setup.SHOP_NAME + '" (Nische: ' + setup.SHOP_NISCHE + ', Zielgruppe: ' + setup.ZIELGRUPPE + '). ' +
  'Der Gruender ist Solo-Unternehmer mit wenig Zeit. Du bist erfahren, direkt und sagst auch unbequeme Wahrheiten.\n\n' +
  'WOCHENDATEN:\n' + daten + '\n\n' +
  'Schreibe dein woechentliches CMO-Briefing fuer die kommende Woche, auf Deutsch (Du-Form):\n' +
  '1. LAGEBERICHT: Wo stehen wir? Sind wir auf Kurs zum Monatsziel? (ehrlich rechnen!)\n' +
  '2. DIE 3 PRIORITAETEN der Woche (konkret, mit Zeitaufwand-Schaetzung, wichtigste zuerst)\n' +
  '3. BUDGET-EMPFEHLUNG: Wie das Marketing-Budget diese Woche aufteilen (Ads / Content / Sonstiges) und warum\n' +
  '4. EIN WACHSTUMS-EXPERIMENT fuer die Woche (Hypothese, Umsetzung, Erfolgskriterium)\n' +
  '5. STOPP-LISTE: Eine Sache, die der Gruender diese Woche NICHT tun sollte (Zeitfresser/Ablenkung)\n\n' +
  'Antworte NUR mit validem JSON, ohne Markdown-Codeblock:\n' +
  '{"telegram_kurz": "<max 800 Zeichen Kurzfassung: Lage in 2 Saetzen + die 3 Prioritaeten als Stichpunkte>", "html": "<das volle Briefing als sauberes HTML mit h2/h3, Listen, ohne html/body-Geruest>"}';

return [{ json: { prompt } }];

const blocks = $json.content || [];
const text = (blocks.find(b => b.type === 'text') || {}).text || '';
let daten;
try {
  daten = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch (e) {
  daten = { telegram_kurz: text.slice(0, 800), html: '<pre style="white-space:pre-wrap;font-family:sans-serif;">' + text + '</pre>' };
}
const setup = $('⚙️ Setup').first().json;
return { json: {
  betreff: '🧠 CMO-Briefing fuer die Woche · ' + setup.SHOP_NAME,
  email_html: '<div style="font-family:sans-serif;max-width:640px;margin:0 auto;">' + daten.html + '</div>',
  telegram_text: '🧠 CMO-BRIEFING · ' + setup.SHOP_NAME + '\n━━━━━━━━━━━━━━━━━━\n\n' + daten.telegram_kurz + '\n\n📧 Das volle Briefing liegt in deinem Postfach.'
}};
